const fs = require('fs');
const path = require('path');

function walk(dir) {
    let results = [];
    const list = fs.readdirSync(dir);
    list.forEach(function(file) {
        file = dir + '/' + file;
        const stat = fs.statSync(file);
        if (stat && stat.isDirectory()) { 
            results = results.concat(walk(file));
        } else { 
            if (file.endsWith('.js') || file.endsWith('.jsx')) {
                results.push(file);
            }
        }
    });
    return results;
}

const files = walk('./src');
files.forEach(file => {
    let content = fs.readFileSync(file, 'utf8');

    // Replace const fn = async (...) => { with async function fn(...) {
    content = content.replace(/const\s+(\w+)\s*=\s*async\s*\((.*?)\)\s*=>\s*\{/g, 'async function $1($2) {');

    // Replace const fn = (...) => { with function fn(...) {
    // Only if they are simple arrow functions that don't bind this. For safety, let's just do async for now since that's what was failing.
    content = content.replace(/const\s+(\w+)\s*=\s*\((.*?)\)\s*=>\s*\{/g, 'function $1($2) {');

    // Fix empty catch blocks
    content = content.replace(/catch\s*\((.*?)\)\s*\{\s*\}/g, 'catch ($1) { console.error($1); }');
    content = content.replace(/catch\s*\{\s*\}/g, 'catch (e) { console.error(e); }');

    // Fix empty if/else blocks (just putting a comment inside)
    content = content.replace(/\{\s*\}/g, (match, offset, string) => {
        // Simple heuristic to avoid replacing object literals
        if (string.slice(offset - 5, offset).includes(')')) return '{ /* empty */ }';
        return match;
    });

    fs.writeFileSync(file, content, 'utf8');
    console.log('Processed', file);
});

self.addEventListener('push', function(event) {
    let data = {};
    if (event.data) {
        try {
            data = event.data.json();
        } catch (e) {
            data = { title: 'New notification', body: event.data.text() };
        }
    }

    const title = data.title || 'ACN+';
    const options = {
        body: data.body || 'You have new activity!',
        icon: '/vite.svg',
        badge: '/vite.svg',
        data: {
            url: data.url || '/'
        }
    };

    event.waitUntil(
        self.registration.showNotification(title, options)
    );
});

self.addEventListener('notificationclick', function(event) {
    event.notification.close();
    if (event.notification.data && event.notification.data.url) {
        event.waitUntil(
            clients.matchAll({ type: 'window' }).then(windowClients => {
                // Check if there is already a window/tab open with the target URL
                for (let i = 0; i < windowClients.length; i++) {
                    let client = windowClients[i];
                    if (client.url === event.notification.data.url && 'focus' in client) {
                        return client.focus();
                    }
                }
                // If not, open a new window
                if (clients.openWindow) {
                    return clients.openWindow(event.notification.data.url);
                }
            })
        );
    }
});

import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Sparkles, X, Send, Brain } from 'lucide-react';
import api from '../lib/api';

export default function AIFloatingAssistant() {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSend = async () => {
    if (!input.trim() || loading) return;
    const userMsg = input;
    setMessages(prev => [...prev, { role: 'user', content: userMsg }]);
    setInput('');
    setLoading(true);

    try {
      const res = await api.post('/api/ai/ask', { question: userMsg });
      setMessages(prev => [...prev, { role: 'ai', content: res.answer }]);
    } catch (err) {
      setMessages(prev => [...prev, { role: 'ai', content: 'Oops! I hit a snag. Try again?' }]);
    } finally {
      setLoading(false);
    }
  };

  return (
    <>
      {/* Floating Toggle Button */}
      <motion.button
        className="ai-fab"
        whileHover={{ scale: 1.1 }}
        whileTap={{ scale: 0.9 }}
        onClick={() => setIsOpen(!isOpen)}
        style={{
             position: 'fixed',
             bottom: '180px',
             right: '24px',
             width: '56px',
             height: '56px',
             borderRadius: '50%',
             background: 'linear-gradient(135deg, #22d3ee, #0891b2)',
             color: 'white',
             display: 'flex',
             alignItems: 'center',
             justifyContent: 'center',
             boxShadow: '0 8px 24px rgba(34, 211, 238, 0.4)',
             zIndex: 999
        }}
      >
        {isOpen ? <X size={24} /> : <Sparkles size={24} />}
      </motion.button>

      <AnimatePresence>
        {isOpen && (
          <motion.div
            initial={{ opacity: 0, y: 20, scale: 0.95 }}
            animate={{ opacity: 1, y: 0, scale: 1 }}
            exit={{ opacity: 0, y: 20, scale: 0.95 }}
            className="ai-compact-window"
          >
            <div className="ai-window-header">
              <div className="header-title">
                <Brain size={18} />
                <span>Study Companion</span>
              </div>
              <Sparkles size={16} className="pulse-icon" />
            </div>

            <div className="ai-window-messages">
              {messages.length === 0 && (
                <div className="ai-empty-state">
                  <p>How can I help you with your studies today?</p>
                </div>
              )}
              {messages.map((m, i) => (
                <div key={i} className={`mini-msg ${m.role}`}>
                  {m.content}
                </div>
              ))}
              {loading && <div className="mini-msg ai dots">...</div>}
            </div>

            <div className="ai-window-input">
              <input 
                placeholder="Ask your buddy..." 
                value={input}
                onChange={e => setInput(e.target.value)}
                onKeyDown={e => e.key === 'Enter' && handleSend()}
              />
              <button onClick={handleSend} disabled={loading}>
                <Send size={16} />
              </button>
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      <style>{`
        .ai-compact-window {
          position: fixed;
          bottom: 250px;
          right: 24px;
          width: 320px;
          height: 400px;
          background: rgba(15, 15, 18, 0.95);
          backdrop-filter: blur(20px);
          -webkit-backdrop-filter: blur(20px);
          border: 1px solid rgba(255, 255, 255, 0.1);
          border-radius: 24px;
          display: flex;
          flex-direction: column;
          overflow: hidden;
          z-index: 1001;
          box-shadow: 0 20px 50px rgba(0,0,0,0.5);
        }

        .ai-window-header {
          padding: 16px;
          background: rgba(255, 255, 255, 0.03);
          border-bottom: 1px solid rgba(255, 255, 255, 0.05);
          display: flex;
          justify-content: space-between;
          align-items: center;
        }

        .header-title {
          display: flex;
          align-items: center;
          gap: 8px;
          font-weight: 700;
          font-size: 14px;
          color: #22d3ee;
        }

        .ai-window-messages {
          flex: 1;
          overflow-y: auto;
          padding: 16px;
          display: flex;
          flex-direction: column;
          gap: 12px;
        }

        .mini-msg {
          max-width: 85%;
          padding: 8px 12px;
          font-size: 13px;
          line-height: 1.4;
          border-radius: 12px;
        }
        .mini-msg.user {
          align-self: flex-end;
          background: #22d3ee;
          color: black;
          border-bottom-right-radius: 2px;
        }
        .mini-msg.ai {
          align-self: flex-start;
          background: rgba(255, 255, 255, 0.08);
          color: white;
          border-bottom-left-radius: 2px;
        }

        .ai-window-input {
          padding: 12px;
          background: rgba(255, 255, 255, 0.02);
          display: flex;
          gap: 8px;
        }
        .ai-window-input input {
          flex: 1;
          background: rgba(255, 255, 255, 0.05);
          border: 1px solid rgba(255, 255, 255, 0.1);
          border-radius: 12px;
          padding: 8px 12px;
          color: white;
          font-size: 13px;
        }
        .ai-window-input button {
          background: #22d3ee;
          color: black;
          width: 36px;
          height: 36px;
          border-radius: 10px;
          display: flex;
          align-items: center;
          justify-content: center;
        }

        .pulse-icon {
          animation: pulse 2s infinite;
          color: rgba(34, 211, 238, 0.5);
        }

        @keyframes pulse {
          0% { transform: scale(1); opacity: 0.5; }
          50% { transform: scale(1.2); opacity: 1; }
          100% { transform: scale(1); opacity: 0.5; }
        }
      `}</style>
    </>
  );
}

import { NavLink, useLocation } from 'react-router-dom';
import { motion } from 'framer-motion';
import { Home, Compass, Plus, MessageCircle, User } from 'lucide-react';

const navItems = [
  { path: '/',        icon: Home,          label: 'Feed'    },
  { path: '/explore', icon: Compass,       label: 'Explore' },
  { path: '/create',  icon: Plus,          label: 'Post',   isCreate: true },
  { path: '/chat',    icon: MessageCircle, label: 'Chat'    },
  { path: '/profile', icon: User,          label: 'You'     },
];

export default function BottomNav() {
  const location = useLocation();

  const hideOn = ['/login', '/signup'];
  if (hideOn.includes(location.pathname)) return null;
  if (location.pathname.match(/^\/chat\/.+/) || location.pathname.match(/^\/partner-chat\/.+/)) return null;

  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Sora:wght@400;500;600&display=swap');

        .bnav-root {
          position: fixed;
          bottom: 0; left: 0; right: 0;
          z-index: 1000;
          display: flex;
          justify-content: center;
          padding: 0 0 env(safe-area-inset-bottom, 0px);
          pointer-events: none;
        }

        .bnav-bar {
          pointer-events: auto;
          width: 100%;
          max-width: 480px;
          background: rgba(8, 8, 10, 0.92);
          backdrop-filter: blur(24px) saturate(160%);
          -webkit-backdrop-filter: blur(24px) saturate(160%);
          border-top: 0.5px solid rgba(240, 237, 232, 0.07);
          display: flex;
          align-items: stretch;
          padding: 8px 4px calc(8px + env(safe-area-inset-bottom, 0px));
        }

        .bnav-item {
          flex: 1;
          display: flex;
          flex-direction: column;
          align-items: center;
          justify-content: center;
          gap: 5px;
          text-decoration: none;
          padding: 4px 0;
          -webkit-tap-highlight-color: transparent;
          position: relative;
        }

        .bnav-icon-wrap {
          width: 44px;
          height: 30px;
          border-radius: 10px;
          display: flex;
          align-items: center;
          justify-content: center;
          transition: background 0.18s ease;
          position: relative;
        }

        .bnav-icon-wrap.active {
          background: rgba(240, 237, 232, 0.09);
        }

        .bnav-create {
          width: 44px;
          height: 30px;
          border-radius: 10px;
          background: #f0ede8;
          display: flex;
          align-items: center;
          justify-content: center;
        }

        .bnav-label {
          font-family: 'Sora', sans-serif;
          font-size: 10px;
          font-weight: 500;
          letter-spacing: 0.2px;
          line-height: 1;
          transition: color 0.18s ease;
        }

        .bnav-label.active {
          font-weight: 600;
          color: #f0ede8;
        }

        .bnav-label.inactive {
          color: rgba(240, 237, 232, 0.3);
        }

        .bnav-badge {
          position: absolute;
          top: 2px;
          right: 6px;
          width: 7px;
          height: 7px;
          border-radius: 50%;
          background: #ef4444;
          border: 1.5px solid #08080a;
        }
      `}</style>

      <nav className="bnav-root" aria-label="Main navigation">
        <div className="bnav-bar">
          {navItems.map(({ path, icon: Icon, label, isCreate, badge }) => {
            const isActive = path === '/'
              ? location.pathname === '/'
              : location.pathname.startsWith(path);

            return (
              <NavLink key={path} to={path} className="bnav-item">
                <motion.div
                  whileTap={{ scale: 0.80 }}
                  transition={{ type: 'spring', stiffness: 480, damping: 22 }}
                  style={{ position: 'relative', display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 5 }}
                >
                  {isCreate ? (
                    <div className="bnav-create">
                      <Icon size={17} color="#08080a" strokeWidth={2.5} />
                    </div>
                  ) : (
                    <div className={`bnav-icon-wrap ${isActive ? 'active' : ''}`}>
                      <Icon
                        size={20}
                        color={isActive ? '#f0ede8' : 'rgba(240,237,232,0.32)'}
                        strokeWidth={isActive ? 2.2 : 1.6}
                      />
                    </div>
                  )}

                  {badge && <div className="bnav-badge" />}

                  <span className={`bnav-label ${isActive ? 'active' : 'inactive'}`}>
                    {label}
                  </span>

                  {isActive && !isCreate && (
                    <motion.div
                      layoutId="bnav-active-dot"
                      style={{
                        width: 3,
                        height: 3,
                        borderRadius: '50%',
                        background: 'rgba(240,237,232,0.5)',
                        position: 'absolute',
                        bottom: -6,
                      }}
                      transition={{ type: 'spring', bounce: 0.2, duration: 0.45 }}
                    />
                  )}
                </motion.div>
              </NavLink>
            );
          })}
        </div>
      </nav>
    </>
  );
}

