                  animate={{ opacity: 1, scale: 1 }}
                  transition={{ delay: i * 0.1 }}
                >
                  <PostCard post={post} onUpdate={loadProfile} />
                </motion.div>
              ))
              )
            )}

            {activeTab === 'reels' && (
              reels.length === 0 ? (
                <div className="empty-portfolio">
                  <Film size={40} />
                  <p>No reels captured yet.</p>
